#include <bits/stdc++.h>
using namespace std;

int par[100001];
int find(int x){ return par[x]==x?x:par[x]=find(par[x]); }
bool uni(int a,int b){ int ra=find(a),rb=find(b); if(ra==rb) return false; par[ra]=rb; return true; }

struct E{ int u,v,w; };

int main() {
    ios_base::sync_with_stdio(false); cin.tie(NULL);
    int n, k, m; cin >> n >> k >> m;
    for(int i=1;i<=n;i++) par[i]=i;
    int comp=n;
    for(int i=0;i<k;i++){
        int a,b; cin >> a >> b;
        if(uni(a,b)) comp--;
    }
    vector<E> e(m);
    for(int i=0;i<m;i++) cin >> e[i].u >> e[i].v >> e[i].w;
    sort(e.begin(), e.end(), [](const E&a,const E&b){ return a.w < b.w; });
    long long total=0;
    for(int i=0;i<m && comp>1;i++){
        if(uni(e[i].u, e[i].v)){ total+=e[i].w; comp--; }
    }
    if(comp>1) cout << -1 << "\n";
    else cout << total << "\n";
    return 0;
}
